#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1e6+10;long long A[N],B[N],n,*a=A,*b=B,c[N],vis[N];
int main()
{
	n=read();rep(1,n,i)a[i]=a[i-1]+read();rep(1,n,i)b[i]=b[i-1]+read();
	if(a[n]>b[n]){long long *tmp=a;a=b;b=tmp;} memset(vis,-1,sizeof(vis));
	int j=0;rep(0,n,i)
	{
		while(a[i]>=b[j+1]&&j<n)++j;c[i]=j;
		if(~vis[a[i]-b[j]])
		{
			if(a==A)
			{
				int l=vis[a[i]-b[j]]+1,r=i;printf("%d\n",r-l+1);
				rep(l,r,i)printf("%d ",i);putchar('\n');
				l=c[vis[a[i]-b[j]]]+1,r=c[i];printf("%d\n",r-l+1);
				rep(l,r,i)printf("%d ",i);putchar('\n');
			}
			else
			{
				int l=c[vis[a[i]-b[j]]]+1,r=c[i];printf("%d\n",r-l+1);
				rep(l,r,i)printf("%d ",i);putchar('\n');
				l=vis[a[i]-b[j]]+1,r=i;printf("%d\n",r-l+1);
				rep(l,r,i)printf("%d ",i);putchar('\n');
			}
			return 0;
		}
		vis[a[i]-b[j]]=i;
	}
}
